INSERT INTO module_emojis(key,value) VALUES('noPermission','"You do not have permission to manage server emojis."') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
INSERT INTO module_emojis(key,value) VALUES('invalidName','"Invalid emoji name. Use 2–32 characters: letters, numbers, and underscores only."') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
INSERT INTO module_emojis(key,value) VALUES('nameTaken','"An emoji with that name already exists on this server."') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
INSERT INTO module_emojis(key,value) VALUES('notImage','"The attachment must be an image file (PNG, JPEG, GIF, or WebP)."') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
INSERT INTO module_emojis(key,value) VALUES('fileTooLarge','"That image is too large. Discord emojis must be 256 KiB or smaller."') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
INSERT INTO module_emojis(key,value) VALUES('notCustomEmoji','"Only custom emojis can be copied. Paste a custom emoji from another server (not a standard unicode emoji)."') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
INSERT INTO module_emojis(key,value) VALUES('downloadFailed','"Could not download the image. Please try again."') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
INSERT INTO module_emojis(key,value) VALUES('botMissingPermission','"I do not have the Manage Emojis and Stickers permission in this server."') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
INSERT INTO module_emojis(key,value) VALUES('slotsFull','"This server has no remaining emoji slots. Remove an emoji or increase your boost level."') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
INSERT INTO module_emojis(key,value) VALUES('createFailed','"Could not create the emoji. Please try again."') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
INSERT INTO module_emojis(key,value) VALUES('addedSuccess','"Added {emoji} to this server."') ON CONFLICT(key) DO UPDATE SET value=excluded.value;
